import{_ as e,o as t,c as b,j as r,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"穿刺极乐","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/穿刺极乐.md","filePath":"4.资源分区/7.物品与装备/6.套装/穿刺极乐.md"}'),n={name:"4.资源分区/7.物品与装备/6.套装/穿刺极乐.md"};function o(d,a,_,l,i,c){return t(),b("div",null,[...a[0]||(a[0]=[r("h1",{id:"穿刺极乐",tabindex:"-1"},[p("穿刺极乐 "),r("a",{class:"header-anchor",href:"#穿刺极乐","aria-label":'Permalink to "穿刺极乐"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调017")])])],-1),s('<h1 id="穿刺极乐-1" tabindex="-1">穿刺极乐 <a class="header-anchor" href="#穿刺极乐-1" aria-label="Permalink to &quot;穿刺极乐&quot;">​</a></h1><p>穿刺极乐<br> 不要看别处，一直盯着它，让它待在你的视线之内。<br> 穿刺乐园（O-04-72）的造型像是一棵红色的树。它有着一根从地板上延伸出的茎秆以及两块翅状的分支。它的主体呈红色，在中心长有一个巨大的红色眼球，一些较小的眼球长在其他部位。</p><p>它就活在你的视线之中。<br> 当你展开自己的翅膀，向一位被遗忘的神明走近时，<br> 你脚下蠢蠢欲动的大地便已准备好将你送向乐园。</p><p>武器<br> 不要看别处，一直盯着它，让它待在你的视线之内。 它就活在你的视线里，那些收容措施根本连屁都不是。 ?你得将它收容在你的视线之中。 眨眼是没问题的，只是一瞬间的话它还能忍受。<br> 价格：B+2000<br> 这是一把通体血红的长枪，持有它时，你的视野内会出现一些血红色的茎干，不要试图让那些事物从你的视野内消失<br> 武器伤害：18L【破甲6】【格挡2】【长柄】【双手】<br> 深邃的视线：当你攻击一名你能精确定位的单位时，本次攻击将附带【幻灭】效果，<br> 若该单位没有你的精确定位，则这把长枪会开始延伸，使得本次攻击距离将增加30米，同时命中时，将会在下一轮开始时减少命中单位4点ap，持续一轮，这是一个B级的耗竭效果。<br> 它在你的视线中：<br> 当场上所有敌方单位没有你的精确定位时，你的攻击可以瞬间来到任意一名敌人的身边，并将其贯穿，这使得你的攻击附带B级心灵来源的传送攻击效果，同时具备【贯穿】特性</p><p>护甲：<br> 但当它认为你移开注意力时，它就会展开它的翅膀。 ?翅膀，没错，就是翅膀。 ?就仿佛一个被遗忘的神明收取它的祭品一般，那血淋淋的翅膀会盖满整条走廊。 ?它的翅膀上还挂满了果实——由新鲜的尸体所组成的果实。<br> 价格：B+2000<br> 这是一件通体红色的护甲，护甲的正中心有一颗巨大的红色眼球，同时其他部位生长着几颗较小的眼球<br> 盔甲防御：17/17【防弹】【防能量】<br> 他人的视线：你凝视着我……我凝视着你，这件护甲上的眼球不断转动着，注视着周围的一切，你获得B级的魔幻本质侦测能力<br> 萎缩的血翼：这件护甲的身后有着一双小小的如同枝条组成的翅膀一样的事物，但它本身的用处并非飞行，而是在他人的忽视中等待着生长，你获得基于盔甲防御的1点反伤，同时，若所有敌单位未能获得你的精准定位，每有一轮，这个反伤点数+1，当任何单位获得你的精确定位后，反伤点数将不再增长。</p><p>饰品：<br> 如果这样仍然没有吸引到你的注意力的话，那些茎干将会向着光亮处延伸，进而阻碍整个公司的运作。它的翅膀将会伸向天空，遮住太阳，就像个天使一样。如果你终于决定要把你的视线从虚无中拽回来并看向它时，那还有些希望。 ?它会回到那黑暗隐蔽的角落里。当然，前提是你还活着的话。<br> 价格：B+2000<br> 这是一顶由红色荆棘和红色眼球组成的头冠，会占据你的头盔位置<br> 这顶头盔会使得你获得灵感视觉<br> 当你佩戴该头冠时，你会迫不及待地将没有关注你的存在尽数穿刺，因此你的攻击获得了【高速5】<br> 同时，这种欲望会不断的滋生，直到有人把目光放到你的身上，若所有敌单位未能获得你的精准定位，每轮结束时，你获得可叠加的5破甲，至多增加50点，持续一场景。当有任何单位精确定位你之后，这一效果不再增长。<br> 同时，当你受到任意一名敌人的伤害时，若该名敌人的下一次攻击了非你的单位时，你对其下一次攻击检定将额外获得【8加骰】，这个效果将在你被攻击后失效。</p><p>套装效果：<br> 独属于你的天堂：<br> 你只需闭上双眼。没错，就像那样......<br> 如有一日再度睁开双眼，能否在那视线中看见成果？<br> 别来这里......这儿只有一棵满是尖刺的树。并非你的安息之处......<br> 在所有人的关注与视线中......终于结出果实，展翅翱翔。<br> 那展开翅膀之人，献出了一切......<br> 每日一次，消耗一个标准动作可使用，收缩的血翼将会展开，仿佛一个被遗忘的神明收取它的祭品一般，那些茎干将会向着光亮处延伸，伸向天空，遮住太阳，就像个天使一样</p><p>在这一状态下，你无法进行主动移动，你的敏感范围的一半范围内将视为B级心灵来源的困难地形。<br> 你使用穿刺极乐武器的攻击范围变为圆形且范围扩大至敏感范围的一半，可同时攻击范围内所有敌人，你的攻击将附带【吸血7】，命中时，将会令目标单位获得【穿刺易伤7】。<br> 以上效果会持续一个场景,你可以自由动作主动结束这一状态。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',10)])])}const f=e(n,[["render",o]]);export{m as __pageData,f as default};
